using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Tool Definitions ---

/// <summary>Tools available to the research agent.</summary>
static class ResearchTools
{
    private static readonly List<string> _notes = [];

    [Description("Search the web for information on a given query. Returns a list of relevant snippets.")]
    public static string SearchWeb(string query)
    {
        Console.WriteLine($"  [Tool] Searching web for: \"{query}\"");

        // Simulated web search results for demonstration purposes.
        // In production, replace with a real search API (e.g., Bing Search).
        var results = new[]
        {
            new { Title = $"Overview of {query}", Snippet = $"{query} is a broad and evolving topic with significant recent developments in research and industry applications." },
            new { Title = $"Recent advances in {query}", Snippet = $"Recent advances in {query} include improved efficiency, new frameworks, and wider adoption across sectors." },
            new { Title = $"{query} challenges and outlook", Snippet = $"Key challenges facing {query} include scalability, cost, ethical considerations, and the need for robust evaluation methods." }
        };

        return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
    }

    [Description("Save a note for later use in the research summary. Use this to record key findings.")]
    public static string TakeNote(string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  [Tool] Note saved ({_notes.Count} total)");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieve all saved notes.")]
    public static string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n---\n", _notes.Select((n, i) => $"Note {i + 1}: {n}"));
    }
}

// --- Main Program ---

Console.WriteLine("=== AI Research Agent ===\n");

var topic = args.Length > 0 ? string.Join(' ', args) : "quantum computing";
Console.WriteLine($"Researching topic: \"{topic}\"\n");

// Configure the AI client (uses OPENAI_API_KEY and optionally OPENAI_BASE_URL env vars)
var endpoint = Environment.GetEnvironmentVariable("OPENAI_BASE_URL");
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "no-key";
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

OpenAIClientOptions? options = endpoint is not null
    ? new() { Endpoint = new Uri(endpoint) }
    : null;

var openAiClient = new OpenAIClient(apiKey, options);

IChatClient chatClient = openAiClient.GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(ResearchTools.SearchWeb),
        AIFunctionFactory.Create(ResearchTools.TakeNote),
        AIFunctionFactory.Create(ResearchTools.GetNotes),
    ]
};

var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your goal is to research the given topic thoroughly by:
        1. Searching the web for relevant information (make 2-3 searches with different queries)
        2. Taking notes on key findings as you go
        3. After gathering enough information, retrieve your notes and produce a final summary

        Be methodical: search, take notes on important points, then summarize.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a comprehensive summary: {topic}")
};

Console.WriteLine("Agent is working...\n");

var response = await chatClient.GetResponseAsync(messages, chatOptions);

Console.WriteLine("\n=== Research Summary ===\n");
Console.WriteLine(response.Text);

